import React from 'react';
import Sidebar from './Sidebar';
import TopWorstSellers from './TopWorstSellers'; // Import nieuw component
import './Layout.css';
import '../index.css';

const Layout = ({ children, onSelectionChange }) => {
    const segments = [
        { name: 'Rum-based', value: '12.312' },
        { name: 'Whisky infused', value: '1453' },
        { name: 'Wodka-based', value: '854' },
        { name: 'Gin-based', value: '652' },
    ];

    const items = [
        { name: 'Bacardi cola' },
        { name: 'Gin tonic' },
        { name: 'Mojito' },
        { name: 'Whiskey sour' },
        { name: 'Espresso koffie' },
    ];

    return (
        <div className="layout-container">
            {/* Sidebar */}
            <Sidebar onSelectionChange={onSelectionChange} />

            {/* Main Content */}
            <div className="main-content">
                <TopWorstSellers segments={segments} items={items} />
                {children} {/* Render wrapped content */}
            </div>

            {/* Filter Bar */}
            <div className="filter-bar">
                <div className="filter-header">Filters</div>
                <ul className="filter-options">
                    <li>
                        <input type="checkbox" id="option1" />
                        <label htmlFor="option1">Option 1</label>
                    </li>
                    <li>
                        <input type="checkbox" id="option2" />
                        <label htmlFor="option2">Option 2</label>
                    </li>
                    <li>
                        <input type="checkbox" id="option3" />
                        <label htmlFor="option3">Option 3</label>
                    </li>
                </ul>
            </div>
        </div>
    );
};

export default Layout;
